// Normalizar payload de Chatwoot
const raw = $input.first().json.body || $input.first().json;
const data = raw.data || raw;

// ---- Teléfono del cliente ----
let phone = '';
const senderPhone = data?.conversation?.meta?.sender?.phone_number;
const sourceId    = data?.conversation?.contact_inbox?.source_id;

if (senderPhone) {
  phone = senderPhone.replace(/[^0-9]/g, '');
} else if (sourceId) {
  phone = sourceId.split('@')[0].replace(/[^0-9]/g, '');
}

// Normalizar: si tiene prefijo Colombia (57) y 12 dígitos → quitar prefijo
if (phone.startsWith('57') && phone.length === 12) {
  phone = phone.substring(2);
}

// ---- Adjuntos ----
const attachments = data?.attachments || [];
const imageExts   = ['jpg', 'jpeg', 'png', 'webp', 'gif', 'pdf', 'bmp'];

const imageAttachment = attachments.find(a => {
  const isImageType = ['image', 'file'].includes((a.file_type || '').toLowerCase());
  const isImageExt  = imageExts.includes((a.extension || '').toLowerCase());
  const urlHasImg   = imageExts.some(ext => (a.data_url || a.file_url || '').toLowerCase().includes('.' + ext));
  return isImageType || isImageExt || urlHasImg;
});

const attachmentUrl  = imageAttachment?.data_url || imageAttachment?.file_url || '';
const conversationId = data?.conversation?.id || data?.conversation_id || null;
const messageContent = (data?.content || '').toLowerCase();
const isIncoming     = (data?.message_type ?? -1) === 0;
const isPrivate      = data?.private === true;

const paymentKeywords = ['pago', 'soporte', 'comprobante', 'transferencia',
  'nequi', 'bancolombia', 'daviplata', 'recibo', 'consignacion'];
const textSuggestsPayment = paymentKeywords.some(kw => messageContent.includes(kw));
const shouldProcess = isIncoming && !isPrivate && !!attachmentUrl;

return [{
  json: {
    phone,
    conversationId,
    attachmentUrl,
    messageContent: data?.content || '',
    hasImageAttachment: !!attachmentUrl,
    isIncoming,
    isPrivate,
    textSuggestsPayment,
    shouldProcess,
    senderName: data?.conversation?.meta?.sender?.name || 'Cliente',
    inboxId: data?.conversation?.inbox_id || data?.inbox_id || null
  }
}];

const { phone, conversationId, attachmentUrl, messageContent, senderName } = $input.first().json;

const prompt = `Eres un asistente que analiza comprobantes de pago de clientes de internet.
Analiza la imagen y determina si es un comprobante/soporte/recibo de pago.

Si ES un comprobante, responde SOLO con este JSON:
{"es_comprobante":true,"monto":85000,"metodo":"nequi","referencia":"1234567890","fecha":"2026-03-02","confianza":0.95}

Valores validos para metodo: nequi, bancolombia, daviplata, transferencia, efectivo, otro
Fecha en formato YYYY-MM-DD. Monto como numero entero sin puntos (ej: 85000).

Si NO es comprobante, responde SOLO: {"es_comprobante":false}

Contexto del mensaje: "${messageContent}"`;

return [{
  json: {
    phone,
    conversationId,
    attachmentUrl,
    senderName,
    openaiPayload: {
      model: 'gpt-4o-mini',
      messages: [{
        role: 'user',
        content: [
          { type: 'text', text: prompt },
          { type: 'image_url', image_url: { url: attachmentUrl, detail: 'low' } }
        ]
      }],
      max_tokens: 300,
      response_format: { type: 'json_object' }
    }
  }
}];

const aiResp = $input.first().json;
const prev   = $('Preparar Llamada a OpenAI').first().json;

const phone          = prev.phone;
const conversationId = prev.conversationId;
const senderName     = prev.senderName;
const attachmentUrl  = prev.attachmentUrl;

let parsed = { es_comprobante: false };
try {
  const content = aiResp?.choices?.[0]?.message?.content || '{}';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch (e) {
  parsed = { es_comprobante: false, _error: e.message };
}

let monto = 0;
if (parsed.monto != null) {
  const raw = String(parsed.monto).replace(/[^0-9,.]/g, '');
  const norm = raw.includes('.') && !raw.includes(',') && raw.split('.')[1]?.length === 3
    ? raw.replace('.', '') : raw.replace(',', '.');
  monto = parseFloat(norm) || 0;
}

let fecha = parsed.fecha || new Date().toISOString().split('T')[0];
if (!/^\d{4}-\d{2}-\d{2}$/.test(fecha)) fecha = new Date().toISOString().split('T')[0];

const referencia = String(parsed.referencia || `WA-${Date.now()}`).substring(0, 50);
const metodo     = parsed.metodo || 'otro';
const confianza  = parseFloat(parsed.confianza) || 0;

return [{
  json: {
    phone,
    conversationId,
    senderName,
    attachmentUrl,
    esComprobante: parsed.es_comprobante === true && monto > 0,
    monto,
    metodo,
    referencia,
    fecha,
    confianza,
    confianzaAlta: confianza >= 0.7
  }
}];

const crmResp = $input.first().json;
const pago    = $('Procesar Respuesta IA').first().json;

// Respuesta CRM: {clientId, clientName, totalDebt, pendingInvoices}
const clientFound   = crmResp?.clientId !== undefined && crmResp?.clientId !== null;
const clientName    = crmResp?.clientName || pago.senderName || 'Cliente';
const pendingAmount = crmResp?.totalDebt || pago.monto;
const hasDebt       = (crmResp?.totalDebt || 0) > 0 || (crmResp?.pendingInvoices?.length || 0) > 0;

return [{
  json: {
    clientFound,
    clientName,
    pendingAmount,
    hasDebt,
    phone:          pago.phone,
    conversationId: pago.conversationId,
    senderName:     pago.senderName,
    attachmentUrl:  pago.attachmentUrl,
    monto:          pago.monto,
    metodo:         pago.metodo,
    referencia:     pago.referencia,
    fecha:          pago.fecha,
    confianza:      pago.confianza
  }
}];

const reg  = $input.first().json;
const pago = $('Combinar Datos CRM + Pago').first().json;

const montoFmt = new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', maximumFractionDigits: 0 }).format(pago.monto);
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const nombre  = reg?.client || reg?.clientName || pago.clientName || pago.senderName || 'cliente';
const mesPago = reg?.month || `${meses[new Date().getMonth()]} ${new Date().getFullYear()}`;

const icons = { nequi: '🟣', bancolombia: '🟡', daviplata: '🔴', transferencia: '🏦', efectivo: '💵', otro: '💳' };
const icon = icons[pago.metodo] || '💳';

const mensaje = `✅ *¡Pago registrado exitosamente!*

Hola ${nombre}, hemos verificado y registrado tu comprobante:

${icon} *Método:* ${pago.metodo.charAt(0).toUpperCase() + pago.metodo.slice(1)}
💰 *Monto:* ${montoFmt}
🔖 *Referencia:* ${pago.referencia}
📅 *Fecha:* ${pago.fecha}
📋 *Periodo:* ${mesPago}

¡Gracias por tu pago! 🙏`;

return [{
  json: {
    conversationId: pago.conversationId,
    mensaje,
    paymentId: reg?.paymentId,
    clientName: nombre
  }
}];

